UPDATE runs
SET process_id = #{processId},
    command_line = #{commandLine},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND lifecycle = 'running'

UPDATE runs
SET external_session_id_after = #{externalSessionIdAfter},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND lifecycle = 'running'
